        // --- NHÀ MÁY: CHẾ TẠO NÚT TAB RESPONSIVE TỰ ĐỔI MÀU NỀN & VẼ LẠI ICON ---
        function createTabBtn(parent, iconOnBin, iconOffBin, tooltip) {
            var btn = parent.add("group");
            btn.alignment = ["fill", "fill"]; 
            btn.preferredSize.height = 60; // Gắn cứng chiều cao để thanh Header dãn đúng form chuẩn
            btn.isActive = false;
            btn.helpTip = tooltip;

            // Load mảng Binary vào bộ nhớ hệ thống (ScriptUI Image)
            var imgOn = null, imgOff = null;
            try {
                if (iconOnBin) imgOn = ScriptUI.newImage(iconOnBin);
                if (iconOffBin) imgOff = ScriptUI.newImage(iconOffBin);
            } catch(e) {}

            // Dùng đồ hoạ (Graphics) để vẽ TOÀN BỘ cả Nền, Viền và Image
            btn.onDraw = function() {
                var g = this.graphics;
                var w = this.size[0];
                var h = this.size[1];
                
                // 1. VẼ MÀU NỀN
                g.newPath();
                g.rectPath(0, 0, w, h);
                if (this.isActive) {
                    g.fillPath(g.newBrush(g.BrushType.SOLID_COLOR, [0.15, 0.15, 0.15, 1])); // Màu #262626
                }
                
                // 2. VẼ VIỀN STROKE (DÀY 3PX)
                g.strokePath(g.newPen(g.PenType.SOLID_COLOR, [0.25, 0.25, 0.25, 1], 2));

                // 3. VẼ ICON TRỰC TIẾP LÊN NỀN BẰNG DRAW_IMAGE
                var currentImg = this.isActive ? imgOn : imgOff;
                if (currentImg) {
                    var imgW = currentImg.size[0];
                    var imgH = currentImg.size[1];
                    // Thuật toán trừ nửa chênh lệch để căn ảnh vào chính giữa toán học của nút
                    var imgX = (w - imgW) / 2;
                    var imgY = (h - imgH) / 2;
                    g.drawImage(currentImg, imgX, imgY);
                }
            };

            // Hàm kích hoạt thay đổi giao diện
            btn.setActive = function(state) {
                this.isActive = state;
                try { this.notify("onDraw"); } catch(e){} // Bắn tín hiệu ép nút vẽ lại toàn bộ
            };

            // Bắn sự kiện ra ngoài khi click
            function triggerClick() { if (typeof btn.onClick === "function") btn.onClick(); }
            btn.addEventListener("mousedown", triggerClick);

            return btn;
        }

        // TẠO 4 NÚT TAB
        var tabBtnTinh = createTabBtn(tabHeader, iconTinh_ON, iconTinh_OFF, "Tab Clone Tĩnh");
        var tabBtnTron = createTabBtn(tabHeader, iconTron_ON, iconTron_OFF, "Tab Clone Tròn");
        var tabBtnPath = createTabBtn(tabHeader, iconPath_ON, iconPath_OFF, "Tab Clone Path");
        var tabBtnTools = createTabBtn(tabHeader, iconTools_ON, iconTools_OFF, "Tab Tools");

        

        // 2. VÙNG CHỨA NỘI DUNG (STACK)
        var tabContent = topGroup.add("group");
        tabContent.orientation = "stack"; 
        tabContent.alignment = ["fill", "fill"];
        tabContent.alignChildren = ["fill", "fill"];
        tabContent.margins = 5; 

        // 3. TẠO CÁC GROUP NỘI DUNG
        var tabTinh = tabContent.add("group");
        tabTinh.orientation = "column";
        tabTinh.alignChildren = ["center", "top"];

        var tabTron = tabContent.add("group");
        tabTron.orientation = "column";
        tabTron.alignChildren = ["center", "top"];

        var tabPath = tabContent.add("group");
        tabPath.orientation = "column";
        tabPath.alignChildren = ["center", "top"];

        var tabTools = tabContent.add("group");
        tabTools.orientation = "column";
        tabTools.alignChildren = ["center", "top"];

        // ==========================================
        // VÁ LỖI NÚT CLONE BẰNG TPANEL GIẢ (MOCK OBJECT)
        // ==========================================
        // Tạo một tpanel giả để đánh lừa thuật toán bên dưới của bạn
        var tpanel = {
            selection: { text: "Tĩnh", index: 0, name: "Tĩnh" }
        };

        // 4. LOGIC CHUYỂN TAB BẰNG CÁCH BẬT/TẮT VISIBLE
        function switchTab(activeGroup) {
            // A. Ẩn tất cả nội dung Group
            tabTinh.visible = false;
            tabTron.visible = false;
            tabPath.visible = false;
            tabTools.visible = false;
            
            // B. Đặt tất cả các Tab về trạng thái Tối (Inactive)
            tabBtnTinh.setActive(false);
            tabBtnTron.setActive(false);
            tabBtnPath.setActive(false);
            tabBtnTools.setActive(false);

            // C. Bật Group nội dung được chọn lên
            activeGroup.visible = true; 

            // D. Bật Giao diện Tab tương ứng lên màu Đen #262626 và ghi data giả
            if (activeGroup === tabTinh) {
                tabBtnTinh.setActive(true);
                tpanel.selection.text = "Tĩnh";
                tpanel.selection.index = 0;
            }
            else if (activeGroup === tabTron) {
                tabBtnTron.setActive(true);
                tpanel.selection.text = "Tròn";
                tpanel.selection.index = 1;
            }
            else if (activeGroup === tabPath) {
                tabBtnPath.setActive(true);
                tpanel.selection.text = "Path";
                tpanel.selection.index = 2;
            }
            else if (activeGroup === tabTools) {
                tabBtnTools.setActive(true);
                tpanel.selection.text = "Tools";
                tpanel.selection.index = 3;
            }

            // --- CẬP NHẬT DYNAMIC HELP ---
            if (typeof helpTextUI !== "undefined") {
                if (activeGroup === tabTinh) {
                    helpTextUI.text = "Clone Tĩnh Guide";
                    helpBtnUI.onClick = function() {
                        alert(
                            "💡 HƯỚNG DẪN CLONE TĨNH\n\n" +
                            "Chế độ này giúp bạn nhân bản nhanh layer tại chỗ.\n\n" +
                            "🔸 SỐ LƯỢNG: Nhập số bản sao bạn muốn tạo.\n" +
                            "🔸 NÚT CLOOONER: Bấm để bắt đầu đúp.\n" +
                            "🔸 🛅 TRUE CLONE (Tàu ngầm): Đúp sâu tận gốc vào các Comp con, tạo ra các bản sao hoàn toàn độc lập trong Project.\n" +
                            "🔸 🗑️ NÚT RESET: Chọn layer/comp đã đúp và xoá TẬN GỐC khỏi Project (hãy cẩn thận!)."
                        );
                    };
                } else if (activeGroup === tabTron) {
                    helpTextUI.text = "Clone Tròn Guide";
                    helpBtnUI.onClick = function() {
                        alert(
                            "💡 HƯỚNG DẪN CLONE TRÒN\n\n" +
                            "Tạo các bản sao phân bổ đều quanh một tâm (Null).\n\n" +
                            "📌 CHUẨN BỊ: Chọn 1 Null (làm tâm) TRƯỚC, giữ Ctrl chọn Layer cần đúp SAU.\n\n" +
                            "🔸 THÔNG SỐ: Số lượng bản sao & Góc xoay giữa chúng.\n" +
                            "🔸 CÁC CHẾ ĐỘ HIỆU ỨNG (Bật/tắt tuỳ ý):\n" +
                            "   • Ferris Wheel: Bản sao luôn hướng về một phía (như đu quay).\n" +
                            "   • 3D Mode: Bật trục X/Y/Z nếu bạn dùng layer 3D.\n" +
                            "   • Twisted: Xoay luỹ tiến tạo hiệu ứng lốc xoáy.\n\n" +
                            "🔸 UPDATE MODE: Chọn Pivot Null và bấm để cập nhật nóng các hiệu ứng vào Rig đang có.\n" +
                            "🔸 🛅 TRUE CLONE (Tàu ngầm): Đúp sâu tận gốc các Comp.\n" +
                            "🔸 🧹 NÚT CLEAN: Giữ lại các bản sao tại chỗ, chỉ dọn dẹp Expression và Null phụ.\n" +
                            "🔸 🗑️ NÚT RESET: Dọn sạch Rig, trả về duy nhất layer nguyên bản."
                        );
                    };
                } else if (activeGroup === tabPath) {
                    helpTextUI.text = "Clone Path Guide";
                    helpBtnUI.onClick = function() {
                        alert(
                            "💡 HƯỚNG DẪN CLONE PATH\n\n" +
                            "Phân bố các bản sao chạy dọc theo một đường Path.\n\n" +
                            "📌 CHUẨN BỊ: Chọn 1 Shape Layer (chứa Path) và 1 Layer cần đúp.\n\n" +
                            "🔸 THÔNG SỐ: Số lượng bản sao & Khoảng cách % giữa chúng.\n" +
                            "🔸 CÁC CHẾ ĐỘ HIỆU ỨNG (Bật/tắt tuỳ ý):\n" +
                            "   • Auto Orient: Bản sao tự động xoay lượn theo đường cong.\n" +
                            "   • Taper: Thu nhỏ dần kích thước ở 2 đầu.\n" +
                            "   • TrimPath FX: Giới hạn vùng hiển thị của các bản sao.\n" +
                            "   • Twisted: Xoắn ốc luỹ tiến dọc theo path.\n" +
                            "   • Delay Offset: Tạo hiệu ứng truyền sóng (caterpillar) trễ frame.\n\n" +
                            "🔸 UPDATE MODE: Chọn Control Null và bấm để cập nhật nóng các hiệu ứng vào Rig đang có.\n" +
                            "🔸 🛅 TRUE CLONE (Tàu ngầm): Đúp sâu tận gốc các Comp.\n" +
                            "🔸 🧹 NÚT CLEAN: Giữ lại layer trên path, xoá Expression dọn dẹp timeline.\n" +
                            "🔸 🗑️ NÚT RESET: Xoá sạch hệ thống Rig, trả về nguyên bản."
                        );
                    };
                } else if (activeGroup === tabTools) {
                    helpTextUI.text = "Tools Guide";
                    helpBtnUI.onClick = function() {
                        alert(
                            "💡 HƯỚNG DẪN TOOLS PHỤ\n\n" +
                            "Công cụ hỗ trợ điều khiển và Rig các layer ĐÃ CÓ SẴN.\n\n" +
                            "🔸 CLOOON THÊM: Chọn Pivot/Control Null của hệ thống cũ, nhập số và bấm để đúp thêm bản sao nối tiếp.\n\n" +
                            "🔸 RIG TO CIRCULAR / PATH:\n" +
                            "   • Hút các layer khác nhau vào hệ thống Cloooner.\n" +
                            "   • Chọn Layer Tâm/Path ĐẦU TIÊN, giữ Ctrl chọn các Layer kia SAU.\n" +
                            "   • Nút Update Mode đi kèm giúp bạn linh hoạt Bật/Tắt hiệu ứng.\n\n" +
                            "🔸 ĐẢO ORDER LAYER:\n" +
                            "   • Chọn nhiều layer để đảo ngược thứ tự (Z-index).\n" +
                            "   • HOẶC chỉ cần chọn Null Pivot, Tool sẽ tự chui vào trong đảo order toàn bộ các Clone."
                        );
                    };
                }
            }

            // Ép AE tính toán lại layout và dãn Sticky Bottom
            panel.layout.layout(true);  
            panel.layout.resize(); 
        }

        // 5. GẮN SỰ KIỆN CLICK VÀO HỆ THỐNG MỚI
        tabBtnTinh.onClick = function() { switchTab(tabTinh); };
