        // --- NHÀ MÁY 1: SẢN XUẤT CHECKBOX V3 (CHỈ CÓ ICON, CÓ TOOLTIP) ---
        function createCustomCheckbox(parentGrp, labelText, defaultVal, imgOnData, imgOffData) {
            // Chỉ cần dùng 1 Stack Group duy nhất để chứa ảnh, bỏ Group Row đi
            var wrap = parentGrp.add("group");
            wrap.orientation = "stack"; 
            
            var imgOff = wrap.add("image", undefined, imgOffData);
            var imgOn = wrap.add("image", undefined, imgOnData);

            // Gắn Label vào dạng Tooltip với tiền tố "Kích hoạt"
            imgOff.helpTip = "Kích hoạt " + labelText;
            imgOn.helpTip = "Kích hoạt " + labelText;

            wrap.value = defaultVal !== undefined ? defaultVal : false;
            imgOn.visible = wrap.value;

            function toggle() {
                wrap.value = !wrap.value;
                imgOn.visible = wrap.value;
                if (typeof wrap.onClick === 'function') wrap.onClick(); // Bắn tín hiệu ra ngoài
            }

            // Gắn sự kiện click
            imgOff.addEventListener("mousedown", toggle);
            imgOn.addEventListener("mousedown", toggle);

            return wrap; 
        }

        // --- NHÀ MÁY 2: SẢN XUẤT CỤM TRỤC XOAY 3D ---
        function createAxisRadio(parentGrp, defaultAxis) {
            var mainGrp = parentGrp.add("group");
            mainGrp.orientation = "column";
            mainGrp.alignChildren = ["center", "top"]; // Đảm bảo căn giữa
            mainGrp.spacing = 5;

            // Dòng Text ở trên
            mainGrp.add("statictext", undefined, "Trục xoay");

            // Hàng chứa 3 nút ở dưới
            var rowGrp = mainGrp.add("group");
            rowGrp.orientation = "row";
            rowGrp.alignChildren = ["center", "center"];
            rowGrp.spacing = 15;

            // Nút X
            var stackX = rowGrp.add("group"); stackX.orientation = "stack";
            var offX = stackX.add("image", undefined, axisX_OFF_Bin);
            var onX = stackX.add("image", undefined, axisX_ON_Bin);
            
            // Nút Y
            var stackY = rowGrp.add("group"); stackY.orientation = "stack";
            var offY = stackY.add("image", undefined, axisY_OFF_Bin);
            var onY = stackY.add("image", undefined, axisY_ON_Bin);

            // Nút Z
            var stackZ = rowGrp.add("group"); stackZ.orientation = "stack";
            var offZ = stackZ.add("image", undefined, axisZ_OFF_Bin);
            var onZ = stackZ.add("image", undefined, axisZ_ON_Bin);

            mainGrp.value = defaultAxis || "X";

            // Cập nhật giao diện (chỉ 1 nút sáng, 2 nút kia ẩn để lộ ảnh tối)
            function updateUI() {
                onX.visible = (mainGrp.value === "X");
                onY.visible = (mainGrp.value === "Y");
                onZ.visible = (mainGrp.value === "Z");
                if (typeof mainGrp.onChange === 'function') mainGrp.onChange(); // Bắn tín hiệu ra ngoài!
            }
            updateUI();

            function setX() { mainGrp.value = "X"; updateUI(); }
            function setY() { mainGrp.value = "Y"; updateUI(); }
            function setZ() { mainGrp.value = "Z"; updateUI(); }

            offX.addEventListener("mousedown", setX); onX.addEventListener("mousedown", setX);
            offY.addEventListener("mousedown", setY); onY.addEventListener("mousedown", setY);
            offZ.addEventListener("mousedown", setZ); onZ.addEventListener("mousedown", setZ);

            return mainGrp;
        }


